LANG_OPTIONS  = ["中文", "英文","韩文","日文", "德文", "法文", "西班牙文","俄文"]
DOMAIN_OPTIONS = ["技术文档", "机械工程", "电化学", "医疗文档", "半导体", "化学", "计算机"]

# ─── 缓存初始化核心服务 ─────────────────────────────────────────────────────────
@st.cache_resource(show_spinner=False)
def load_services():
    """懒加载并缓存核心服务（跨 session 复用）"""
    from config import config
    from translation_core import DocumentTranslator
    from terminology_extraction import TerminologyExtractor
    from corpus.embeddings import EmbeddingService
    from corpus.manager import CorpusManager
    from agent.graph import patent_agent
    from agent.tools import init_tools

    embedding_service = EmbeddingService()
    corpus_manager = CorpusManager(
        qdrant_url=config.QDRANT_URL,
        qdrant_api_key=config.QDRANT_API_KEY,
        collection_name=config.QDRANT_COLLECTION_NAME,
        embedding_service=embedding_service,
    )
    translator = DocumentTranslator(corpus_manager=corpus_manager)
    term_extractor = TerminologyExtractor()
    init_tools(corpus_manager=corpus_manager)

    return {
        "patent_agent":   patent_agent,
        "translator":     translator,
        "term_extractor": term_extractor,
        "config":         config,
    }

# ─── 翻译调用逻辑（复用 api_server 内核）──────────────────────────────────────
def run_translation(
    src_text: str,
    src_lang: str,
    tgt_lang: str,
    domain: str,
    glossary: Optional[Dict[str, str]] = None,
) -> dict:
    services = load_services()
    agent    = services["patent_agent"]
    translator = services["translator"]

    initial_state = {
        "src_text":              src_text,
        "src_lang":              src_lang,
        "tgt_lang":              tgt_lang,
        "domain":                domain,
        "glossary":              glossary or {},
        "domain_prompt":         None,
        "use_corpus":            False,
        "corpus_id":             None,
        "corpus_threshold":      0.85,
        "messages":              [],
        "use_pipeline_fallback": False,
        "retry_count":           0,
        "validation_passed":     False,
        "inconsistencies":       [],
        "translated_chunks":     [],
        "final_translation":     "",
    }

    try:
        result = agent.invoke(initial_state)
        return {
            "ok":          True,
            "translation": result["final_translation"],
            "term_dict":   result.get("term_dict", {}),
            "chunks":      result.get("chunks", []),
            "stats": {
                "source_length":          len(src_text),
                "translation_length":     len(result["final_translation"]),
                "num_chunks":             len(result.get("chunks", [])),
                "terminology_consistent": result.get("validation_passed", False),
                "retry_count":            result.get("retry_count", 0),
            },
            "mode": "agent",
        }
    except Exception as e_agent:
        import traceback
        with open("agent_error.log", "w") as f:
            f.write(traceback.format_exc())
        try:
            partial_term_dict = initial_state.get("term_dict") or {}
            result = translator.translate_document(
                src_text=src_text, src_lang=src_lang, tgt_lang=tgt_lang,
                domain=domain, glossary=partial_term_dict or glossary, parallel=True, max_workers=3,
                use_corpus=False,
            )
            return {
                "ok":          True,
                "translation": result["translation"],
                "term_dict":   result["term_dict"],
                "chunks":      [],
                "stats": {
                    "source_length":          len(src_text),
                    "translation_length":     len(result["translation"]),
                    "num_chunks":             result["statistics"]["num_chunks"],
                    "terminology_consistent": result["statistics"]["terminology_consistent"],
                    "retry_count":            0,
                },
                "mode": "pipeline_fallback",
            }
        except Exception as e_pipe:
            return {"ok": False, "error": str(e_pipe)}

# ─── 解析用户输入的术语表 ─────────────────────────────────────────────────────
def parse_glossary(raw: str) -> Dict[str, str]:
    glossary = {}
    for line in raw.strip().splitlines():
        line = line.strip()
        if not line:
            continue
        parts = [p.strip() for p in line.replace("：", ":").split(":", 1)]
        if len(parts) == 2 and parts[0] and parts[1]:
            glossary[parts[0]] = parts[1]
    return glossary

